function check_send_cross_chain_msg_access_control(address caller, string memory to_chain, address from_address, uint256 to_handler, uint8 payload_type, bytes calldata payload) external {
    // Setup: caller does not have HANDLER_ROLE
    vm.assume(!chakraSettlement.hasRole(HANDLER_ROLE, caller));

    uint256 nonceBefore = chakraSettlement.nonces(from_address);

    vm.prank(caller);
    try chakraSettlement.send_cross_chain_msg(to_chain, from_address, to_handler, payload_type, payload) {
        // If call succeeds without HANDLER_ROLE, invariant is violated
        assert(false);
    } catch {
        // Expected: should revert for unauthorized caller
    }

    // Nonce should not have changed
    assert(chakraSettlement.nonces(from_address) == nonceBefore);
}
